const input = $input.first().json;
let url = input.url || 'https://example.com';
if (!url.startsWith('http')) url = 'https://' + url;

// 1. Performance: 10 requests, measure avg/min/max response time
const times = [];
for (let i = 0; i < 10; i++) {
  const start = Date.now();
  try {
    await helpers.httpRequest({ method: 'HEAD', url, timeout: 10000 });
    times.push(Date.now() - start);
  } catch(e) {
    times.push(-1); // failed
  }
}
const validTimes = times.filter(t => t >= 0);
const avgTime = validTimes.length ? Math.round(validTimes.reduce((a,b) => a+b, 0) / validTimes.length) : -1;
const minTime = validTimes.length ? Math.min(...validTimes) : -1;
const maxTime = validTimes.length ? Math.max(...validTimes) : -1;
const failedRequests = times.filter(t => t < 0).length;

// 2. Full GET request for content analysis
let result;
try {
  result = await helpers.httpRequest({
    method: 'GET', url,
    returnFullResponse: true,
    encoding: 'utf-8',
    json: false,
    timeout: 15000,
    headers: { 'User-Agent': 'n8n-claw Website Checker/1.0' }
  });
} catch(e) {
  return [{ json: { url, error: 'Could not reach website: ' + e.message } }];
}

const headers = result.headers || {};
const body = typeof result.body === 'string' ? result.body : '';
const bodySize = body.length;

// 3. Security headers
const security = {
  https: url.startsWith('https'),
  hsts: headers['strict-transport-security'] || null,
  csp: headers['content-security-policy'] ? 'present' : 'missing',
  xFrameOptions: headers['x-frame-options'] || 'missing',
  xContentTypeOptions: headers['x-content-type-options'] || 'missing',
  referrerPolicy: headers['referrer-policy'] || 'missing',
  xXssProtection: headers['x-xss-protection'] || 'missing'
};

// Count security score (out of 6)
let secScore = 0;
if (security.https) secScore++;
if (security.hsts) secScore++;
if (security.csp !== 'missing') secScore++;
if (security.xFrameOptions !== 'missing') secScore++;
if (security.xContentTypeOptions !== 'missing') secScore++;
if (security.referrerPolicy !== 'missing') secScore++;

// 4. Meta tags & Open Graph
const titleMatch = body.match(/<title[^>]*>([^<]+)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim() : null;

const descMatch = body.match(/<meta\s+name=["']description["']\s+content=["']([^"']*?)["']/i) ||
                  body.match(/<meta\s+content=["']([^"']*?)["']\s+name=["']description["']/i);
const description = descMatch ? descMatch[1] : null;

// Open Graph
const ogTags = {};
const ogRegex = /<meta\s+(?:property|name)=["'](og:[^"']+)["']\s+content=["']([^"']*?)["']/gi;
let ogMatch;
while ((ogMatch = ogRegex.exec(body)) !== null) { ogTags[ogMatch[1]] = ogMatch[2]; }

// 5. JSON-LD structured data
const jsonLdMatches = body.match(/<script\s+type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi) || [];
const jsonLd = jsonLdMatches.map(m => {
  const content = m.match(/>([\s\S]*?)<\/script>/i);
  if (!content) return null;
  try { return JSON.parse(content[1]); } catch(e) { return null; }
}).filter(Boolean);

// 6. robots.txt check
let hasRobots = false;
try {
  const robotsUrl = url.replace(/\/+$/, '').split('/').slice(0, 3).join('/') + '/robots.txt';
  const rr = await helpers.httpRequest({ method: 'HEAD', url: robotsUrl, timeout: 5000, returnFullResponse: true });
  hasRobots = rr.statusCode === 200;
} catch(e) { /* no robots.txt */ }

// 7. Server & tech info
const serverInfo = {
  server: headers['server'] || 'not disclosed',
  poweredBy: headers['x-powered-by'] || null,
  contentType: headers['content-type'] || 'unknown',
  cdn: headers['cf-ray'] ? 'Cloudflare' : headers['x-cdn'] ? headers['x-cdn'] : headers['x-cache'] ? 'CDN detected' : null
};

// 8. Format output
let r = '=== Website Check: ' + url + ' ===\n\n';
r += '--- Performance (10 requests) ---\n';
r += 'Avg: ' + avgTime + 'ms | Min: ' + minTime + 'ms | Max: ' + maxTime + 'ms';
if (failedRequests > 0) r += ' | Failed: ' + failedRequests + '/10';
r += '\nStatus: ' + result.statusCode + '\n';
r += 'Size: ' + (bodySize > 1024 ? Math.round(bodySize/1024) + ' KB' : bodySize + ' bytes') + '\n';

r += '\n--- Security (' + secScore + '/6) ---\n';
r += 'HTTPS: ' + (security.https ? 'yes' : 'NO') + '\n';
r += 'HSTS: ' + (security.hsts ? 'yes' : 'missing') + '\n';
r += 'CSP: ' + security.csp + '\n';
r += 'X-Frame-Options: ' + security.xFrameOptions + '\n';
r += 'X-Content-Type-Options: ' + security.xContentTypeOptions + '\n';
r += 'Referrer-Policy: ' + security.referrerPolicy + '\n';

r += '\n--- Meta & SEO ---\n';
r += 'Title: ' + (title || 'missing') + '\n';
r += 'Description: ' + (description || 'missing') + '\n';
if (Object.keys(ogTags).length > 0) {
  r += 'Open Graph: ' + Object.entries(ogTags).map(([k,v]) => k + '=' + v).join(', ') + '\n';
} else {
  r += 'Open Graph: none\n';
}
r += 'JSON-LD: ' + (jsonLd.length > 0 ? jsonLd.length + ' block(s) found' : 'none') + '\n';

r += '\n--- Technical ---\n';
r += 'Server: ' + serverInfo.server + '\n';
if (serverInfo.poweredBy) r += 'Powered-By: ' + serverInfo.poweredBy + '\n';
if (serverInfo.cdn) r += 'CDN: ' + serverInfo.cdn + '\n';
r += 'robots.txt: ' + (hasRobots ? 'present' : 'missing') + '\n';

return [{ json: { result: r } }];
